<template><main class="page"><div class="game-wrapper"><div v-if="showCountdown" class="countdown-overlay"><div class="countdown-content"><p v-if="game.observer" class="observer-hint">观战中</p><h2 class="countdown-title">{{ game.isWaiting ? '等待开始' : '准备开始' }}</h2><div v-if="game.isCountdown" class="countdown-number">{{ game.countdownSeconds || 'GO!' }}</div><p v-if="game.isCountdown && !game.observer" class="countdown-hint">调整方向键选择朝向，倒计时结束后移动</p><p v-if="game.isWaiting && isHost" class="countdown-hint">点击下方按钮开始游戏</p><GameButton v-if="game.isWaiting && isHost" @click="game.startCountdown">开始游戏</GameButton><p v-if="game.isWaiting && !isHost" class="countdown-hint">等待房主开始游戏...</p></div></div><div class="grid"><GameCanvas /><div class="grid"><LeaderboardPanel :rows="game.state?.leaderboards || []" /><CombatLog /><GameButton @click="game.toggleObserver">{{ game.observer ? '退出观战' : '观战切换' }}</GameButton></div></div></div></main></template><script setup lang="ts">import { computed, onMounted, onUnmounted } from 'vue'; import { useRoute } from 'vue-router'; import { useGameStore } from '../stores/gameStore'; import { websocketService } from '../services/websocketService'; import GameCanvas from '../components/common/GameCanvas.vue'; import LeaderboardPanel from '../components/common/LeaderboardPanel.vue'; import CombatLog from '../components/common/CombatLog.vue'; import GameButton from '../components/common/GameButton.vue'; const route=useRoute(); const game=useGameStore(); const isHost=computed(()=>game.isHost(String(route.params.id))); const showCountdown=computed(()=>game.isCountdown||game.isWaiting); if(!game.state) game.start(String(route.params.id)); function onCountdownTick(payload:any){ if(game.state){ game.state.countdown_seconds=payload.remaining; } } function onGameStarted(){ if(game.state){ game.state.phase=game.state.phase; } } onMounted(()=>{ websocketService.on('GAME_COUNTDOWN_TICK' as any,onCountdownTick); websocketService.on('GAME_STARTED' as any,onGameStarted); }); onUnmounted(()=>{ });</script><style scoped>.game-wrapper{position:relative}.countdown-overlay{position:absolute;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.65);display:flex;align-items:center;justify-content:center;z-index:50;border-radius:8px}.countdown-content{text-align:center;color:#fff;padding:24px}.observer-hint{display:inline-block;padding:4px 16px;background:rgba(242,201,76,0.2);border:1px solid #f2c94c;border-radius:20px;color:#f2c94c;font-size:14px;margin-bottom:12px}.countdown-title{font-size:28px;margin:0 0 20px 0;font-weight:600}.countdown-number{font-size:120px;font-weight:800;line-height:1;margin:20px 0;color:#f2c94c;text-shadow:0 4px 20px rgba(242,201,76,0.5);animation:pulse 1s ease-in-out infinite}@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.15)}}.countdown-hint{margin-top:16px;font-size:16px;opacity:0.85;line-height:1.6}</style>
